// ── Fallback CAPS topic reference — AI Tutor grounding when no library lesson exists ──
// Hand-authored CAPS-aligned topic summaries per subject/grade/term. The Study
// Library is being built one topic at a time (see src/features/study/data/library/registry.ts
// for what's actually authored so far) — this file is NOT that content. It exists
// so the AI Tutor can still ground itself in accurate, real curriculum content for
// any topic a student asks about, even when no real lesson page exists yet.
//
// Do not treat this as lesson content to render in the Study Library UI — it is
// deliberately terser (a few sentences of key concepts + common misconceptions
// per topic, not full worked examples/quizzes). Its only consumer is the AI
// Tutor's grounding/context-building layer (see src/lib/aiTutor/grounding.ts).

export interface FallbackTopic {
  subject: string;       // matches subjects.ts id
  grade: 10 | 11 | 12;
  term: 1 | 2 | 3 | 4;
  topicKey: string;      // stable slug, kebab-case, unique within subject+grade
  topicName: string;     // human-readable CAPS topic name
  summary: string;       // 2-4 sentences: what this topic covers, core ideas
  keyConcepts: string[]; // 3-8 short bullet-style key concepts/terms
  commonMisconceptions: string[]; // 2-5 short, real, well-known student misconceptions for this exact topic
}

