// Lookup helpers
export function fallbackTopicsFor(subject: string, grade: number, term?: number): FallbackTopic[] {
  return FALLBACK_TOPICS.filter(
    (t) => t.subject === subject && t.grade === grade && (term === undefined || t.term === term)
  );
}

export function findFallbackTopic(subject: string, grade: number, topicKey: string): FallbackTopic | undefined {
  return FALLBACK_TOPICS.find((t) => t.subject === subject && t.grade === grade && t.topicKey === topicKey);
}

export function searchFallbackTopics(query: string, grade?: number): FallbackTopic[] {
  const q = query.trim().toLowerCase();
  if (!q) return [];
  return FALLBACK_TOPICS.filter((t) => {
    if (grade !== undefined && t.grade !== grade) return false;
    if (t.topicName.toLowerCase().includes(q)) return true;
    return t.keyConcepts.some((k) => k.toLowerCase().includes(q));
  });
}
